--- feather_gpu.frag
1: #include <flutter/runtime_effect.glsl>
5: // Feather Fractal — z^3 / (1 + |z|^2) + c
6: // The denominator damps large orbits, producing feather-like spiraling arms
7: // and rich filament structure unlike standard polynomial escape-time sets.
8: // Iteration: z_{n+1} = z_n^3 / (1 + |z_n|^2) + c  (Mandelbrot-style, z₀=0, c=pixel)
9: // Derivative (dz/dc): derNew ≈ 3z²·der/denom + 1, der₀=(0,0).
10: //   (Approximate: treats |z|² coefficient as locally constant for the chain rule.)
11: // Effective escape power ≈ 3; smooth coloring divides by log2(3).
12: // Supports normal-map shading (colorScheme 50-63).
13: uniform float uTime;          // 0
14: uniform vec2  uResolution;    // 1-2
15: uniform vec2  uCenter;        // 3-4
16: uniform float uZoom;          // 5
17: uniform float uIterations;    // 6
18: uniform float uBailout;       // 7
19: uniform float uColorScheme;   // 8
20: uniform float uTransparentBg; // 9
32: // colorScheme 0-49: standard palette. 50-63: normal-map (14 angles × 4 palettes).

--- feather_julia_gpu.frag
1: #include <flutter/runtime_effect.glsl>
5: // Feather Julia set: z_{n+1} = z^3 / (1 + |z|^2) + c, c = (0.35, −0.05).
6: // Julia set of the Feather map — pixel = z₀, c = (0.35, −0.05) is fixed.
7: // The Feather map divides the cubic iterate by the scalar (1+|z|²),
8: // softening the growth rate and creating asymmetric feather-like
9: // filaments. Unlike polynomial Julia sets, the bounded component is
10: // only weakly compact — the Julia set has hair-like extensions radiating
11: // outward from a central connected body. Near c=(0.35, −0.05) the set
12: // is connected with three primary arms decorated by fine plume structures.
13: // Derivative: 3z²·der / (1+|z|²) for normal-map shading (approximation).
14: // Supports normal-map shading (colorScheme 50-63).
15: uniform float uTime;
16: uniform vec2  uResolution;
17: uniform vec2  uCenter;
18: uniform float uZoom;
19: uniform float uIterations;
20: uniform float uBailout;
21: uniform float uColorScheme;
22: uniform float uTransparentBg;

