from pathlib import Path
import re, hashlib
root=Path('shaders/escape_time_family/julia_variants')
start_re=re.compile(r'^(?:float|vec[234]|mat[234]|int|bool|void)\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(')
funcs={}
for p in sorted(root.rglob('*.frag')):
    lines=p.read_text().splitlines()
    i=0
    while i < len(lines):
        m=start_re.match(lines[i].strip())
        if m:
            name=m.group(1)
            depth=0; body=[]; started=False
            j=i
            while j < len(lines):
                body.append(lines[j].strip())
                depth += lines[j].count('{') - lines[j].count('}')
                if '{' in lines[j]: started=True
                j+=1
                if started and depth<=0:
                    break
            text='\n'.join(body)
            funcs.setdefault((name, text), []).append(p.relative_to(root).as_posix())
            i=j
        else:
            i+=1
for (name,text),paths in sorted(funcs.items()):
    if len(paths)>=2:
